package be.schaubroeck.lpb.rkm.rekenmotor.util.verdeler;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.MoneyKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementChecker;
import be.schaubroeck.lpb.rkm.rekenmotor.util.verdeler.add.EvenredigeVerdelerAdd;
import be.schaubroeck.lpb.rkm.rekenmotor.util.verdeler.put.EvenredigeVerdelerPut;
import be.schaubroeck.lpb.tools.Money;

import java.util.Collection;

public final class EvenredigeVerdelerFactory {
    private EvenredigeVerdelerFactory() {
    }

    public static EvenredigeVerdeler createEvenredigeVerdelerPut(
            MoneyKey bedragKey, Money totaalBedrag, Collection<LoonElement> loonElementen, LoonElementChecker checker) {
        return new EvenredigeVerdelerPut(bedragKey, totaalBedrag, loonElementen, checker);
    }

    public static EvenredigeVerdeler createEvenredigeVerdelerPut(MoneyKey bedragKey, Money totaalBedrag, Collection<LoonElement> loonElementen) {
        return new EvenredigeVerdelerPut(bedragKey, totaalBedrag, loonElementen);
    }

    public static void verdeelEvenredigPut(MoneyKey bedragKey, Money totaalBedrag, Collection<LoonElement> loonElementen, LoonElementChecker checker) {
        EvenredigeVerdeler verdeler = createEvenredigeVerdelerPut(bedragKey, totaalBedrag, loonElementen, checker);
        verdeler.verdeelEvenredig();
    }

    public static void verdeelEvenredigPut(MoneyKey bedragKey, Money totaalBedrag, Collection<LoonElement> loonElementen) {
        EvenredigeVerdeler verdeler = createEvenredigeVerdelerPut(bedragKey, totaalBedrag, loonElementen);
        verdeler.verdeelEvenredig();
    }

    public static EvenredigeVerdeler createEvenredigeVerdelerAdd(
            MoneyKey bedragKey, Money totaalBedrag, Collection<LoonElement> loonElementen, LoonElementChecker checker) {
        return new EvenredigeVerdelerAdd(bedragKey, totaalBedrag, loonElementen, checker);
    }

    public static EvenredigeVerdeler createEvenredigeVerdelerAdd(MoneyKey bedragKey, Money totaalBedrag, Collection<LoonElement> loonElementen) {
        return new EvenredigeVerdelerAdd(bedragKey, totaalBedrag, loonElementen);
    }

    public static void verdeelEvenredigAdd(MoneyKey bedragKey, Money totaalBedrag, Collection<LoonElement> loonElementen, LoonElementChecker checker) {
        EvenredigeVerdeler verdeler = createEvenredigeVerdelerAdd(bedragKey, totaalBedrag, loonElementen, checker);
        verdeler.verdeelEvenredig();
    }

    public static void verdeelEvenredigAdd(MoneyKey bedragKey, Money totaalBedrag, Collection<LoonElement> loonElementen) {
        EvenredigeVerdeler verdeler = createEvenredigeVerdelerAdd(bedragKey, totaalBedrag, loonElementen);
        verdeler.verdeelEvenredig();
    }
}
